{{state_descriptions}}: {{
  "current_version": "The unique identifier of the database schema version currently active.",
  "migration_history": "A stack of applied migration IDs, where the last element is the current version.",
  "is_connected": "Indicates if the session currently holds an active connection to the database instance.",
  "transaction_active": "Boolean flag indicating if a database transaction block is currently open.",
  "locked_tables": "A list of table names that are currently locked by the system, preventing specific modifications.",
  "integrity_status": "The result of the last consistency check (e.g., 'valid', 'corrupted', 'unknown')."
}}
