  "fetch_environment_state": {
    "description": "Retrieves the current state of the database environment, including connection status, active transactions, locked tables, and integrity status.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "is_connected": true,
      "transaction_active": false,
      "locked_tables": [
        "ledger",
        "users"
      ],
      "integrity_status": "corrupted"
    }
  },
  "fetch_migration_lsn": {
    "description": "Queries the migration audit logs to find the Log Sequence Number (LSN) of the last stable checkpoint for a specific tenant prior to a specific migration event.",
    "parameters": {
      "type": "object",
      "properties": {
        "tenant_id": {
          "type": "integer",
          "description": "The unique ID of the tenant."
        },
        "migration_id": {
          "type": "string",
          "description": "The ID of the migration that caused the corruption."
        }
      },
      "required": [
        "tenant_id",
        "migration_id"
      ]
    },
    "example_output": {
      "stable_lsn": "0/16B43C0",
      "timestamp": "2024-07-10T08:00:00Z"
    }
  },
  "clear_resource_lock": {
    "description": "Manually clears resource locks on a specific table to allow administrative operations.",
    "parameters": {
      "type": "object",
      "properties": {
        "table_name": {
          "type": "string",
          "description": "Name of the table to unlock."
        }
      },
      "required": [
        "table_name"
      ]
    },
    "example_output": {
      "status": "success",
      "unlocked_table": "ledger"
    }
  },
  "manage_transaction": {
    "description": "Controls the database transaction state (begin, commit, or rollback).",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "begin",
            "commit",
            "rollback"
          ],
          "description": "The transaction operation to perform."
        }
      },
      "required": [
        "action"
      ]
    },
    "example_output": {
      "transaction_active": true
    }
  },
  "restore_tenant_data": {
    "description": "Restores specific table records for a single tenant to a targeted LSN state. This operation does not affect other tenants.",
    "parameters": {
      "type": "object",
      "properties": {
        "tenant_id": {
          "type": "integer",
          "description": "Target tenant ID."
        },
        "table_name": {
          "type": "string",
          "description": "The table to restore."
        },
        "target_lsn": {
          "type": "string",
          "description": "The Log Sequence Number to restore to."
        }
      },
      "required": [
        "tenant_id",
        "table_name",
        "target_lsn"
      ]
    },
    "example_output": {
      "restored_rows": 1540,
      "status": "completed"
    }
  },
  "realign_identity_sequences": {
    "description": "Re-synchronizes primary key identity sequences to the current maximum value in the table to prevent future PK collisions.",
    "parameters": {
      "type": "object",
      "properties": {
        "table_name": {
          "type": "string",
          "description": "The table whose sequences need realignment."
        }
      },
      "required": [
        "table_name"
      ]
    },
    "example_output": {
      "table": "ledger",
      "new_sequence_start": 55021
    }
  },
  "set_tenant_quarantine": {
    "description": "Updates the quarantine status of a specific tenant.",
    "parameters": {
      "type": "object",
      "properties": {
        "tenant_id": {
          "type": "integer",
          "description": "The unique ID of the tenant."
        },
        "quarantine_active": {
          "type": "boolean",
          "description": "Set to true to quarantine, false to lift."
        }
      },
      "required": [
        "tenant_id",
        "quarantine_active"
      ]
    },
    "example_output": {
      "tenant_id": 505,
      "quarantine_active": false
    }
  }
}
